// Problem: B. SUMdamental Decomposition
// Contest: Codeforces - Codeforces Round 1022 (Div. 2)
// URL: https://codeforces.com/problemset/problem/2108/B
// Memory Limit: 256 MB
// Time Limit: 1000 ms
// 
// Powered by CP Editor (https://cpeditor.org)

#include<bits/stdc++.h>
using namespace std;
int isok(int n){
	if(n&1)return n+1;
	return n;
}
void solve(){
	long long n,k;
	cin>>n>>k;
	int x=__builtin_popcountll(k);
	if(x<n){
	if(x==0){
		if(n==1){
			cout<<"-1"<<endl;
			return;
		}
		else if(n&1){
			cout<<n+3<<endl;
			return;
		}
		else{
			cout<<n<<endl;return;
		}
	}
	else if(x==1){
		if(n==1){
			cout<<k<<endl;
			return ;
		}
		else if(n&1){
			cout<<k+n-x<<endl;
			return;
		}
		else {
			if(k==1){
				cout<<5+n-2<<endl;
				return;
			}
			else{
				cout<<k+n<<endl;
				return;
			}
		}
	}
	else{
		cout<<k+isok(n-x)<<endl;
		return;

	}
	}
	cout<<k<<endl;
	return;

}
int main(){
	int t;
	cin>>t;
	while(t--){
		solve();
	}
	return 0 ;
}

