#include<bits/stdc++.h>
using namespace std;
long long gcd(long long a,long long b){
    return __gcd(a,b);
}
long long lcm(long long a,long long b){
    return (a*b)/gcd(a,b);
}
map<pair<long long ,long long>,long long>poww_data;
long long  poww(long long a,long long b){   
    if(b==0) return 1;
    if(b==1){
        return a;
    }
    else{
        long long mid=b/2;
        if(b&1){
            if(!poww_data.count(make_pair(a,mid))){
                poww_data[make_pair(a,mid)]=poww(a,mid);
            }
            return poww_data[make_pair(a,mid)]*poww_data[make_pair(a,mid)]*a;           
        }
        else{
            if(!poww_data.count(make_pair(a,mid))){
                poww_data[make_pair(a,mid)]=poww(a,mid);
            }
            return poww_data[make_pair(a,mid)]*poww_data[make_pair(a,mid)]; 
        }
    }   
    //time complexity log2(b);
}
vector<int>data={2,3,5,7};
long long total_prime(long long k){
	    long long sum=0;
    for(int a=0;a<2;a++){
        for(int b=0;b<2;b++){
            for(int c=0;c<2;c++){
                for(int d=0;d<2;d++){
                    long long x=lcm(poww(2,a),poww(3,b));
                    x=lcm(x,poww(5,c));
                    x=lcm(x,poww(7,d));
                    if(x!=1){
                    	if((a+b+c+d)&1){
                    		 sum+=k/x;
                    	}
                    	else{
                    		sum-=k/x;
                    	}
                    }                   	
                 }
          }
    }
}


	return sum;

}
void solve(){
    long long n,k;
    cin>>n>>k;
    long long sum=total_prime(k)-total_prime(n-1);
    cout<<k-n+1-sum<<endl;

}
int main(){
    int t;
    cin>>t;
    while(t--){
        solve();
    }
}

