int binaryToDecimal(long long binary) {
    int decimal = 0, i = 0;
    while (binary > 0) {
        int lastDigit = binary % 10;
        decimal += lastDigit * pow(2, i);
        i++;
        binary /= 10;
    }
    return decimal;
}

