import multiprocessing
import time
from tqdm import tqdm

def check_prime(num):
    if num <= 1:
        return False
    elif num == 2 or num == 3:
        return True
    elif num % 2 == 0 or num % 3 == 0:
        return False

    i = 5
    while i * i <= num:
        if num % i == 0 or num % (i + 2) == 0:
            return False
        i += 6
    return True

def find_primes_in_range(args):
    start, end = args
    local_primes = []
    for i in range(start, end + 1):
        if check_prime(i):
            local_primes.append(i)
    return local_primes

if __name__ == "__main__":
    start_r = int(input("Enter starting point: "))
    end_r = int(input("Enter ending point: "))

    start_time = time.time()

    if start_r < 50000 and end_r < 50000:
        primeNumberList = []
        for i in range(start_r, end_r + 1):
            if check_prime(i):
                primeNumberList.append(i)



    elif start_r < 100000 and end_r < 150000:
        cpu_count =multiprocessing.cpu_count()
        print(f"Using {cpu_count} cores...")

        step = (end_r - start_r + 1) // cpu_count
        ranges = []

        for i in range(cpu_count):
            chunk_start = start_r + i * step
            chunk_end = start_r + (i + 1) * step - 1 if i < cpu_count - 1 else end_r
            ranges.append((chunk_start, chunk_end))

        primeNumberList = []

        with multiprocessing.Pool(cpu_count) as pool:
            for result in tqdm(pool.imap(find_primes_in_range, ranges), total=len(ranges), desc="Crunching Primes"):
                primeNumberList.extend(result)     


    else:
        cpu_count = 16 #multiprocessing.cpu_count()
        print(f"Using {cpu_count} cores...")

        step = (end_r - start_r + 1) // cpu_count
        ranges = []

        for i in range(cpu_count):
            chunk_start = start_r + i * step
            chunk_end = start_r + (i + 1) * step - 1 if i < cpu_count - 1 else end_r
            ranges.append((chunk_start, chunk_end))

        primeNumberList = []

        with multiprocessing.Pool(cpu_count) as pool:
            for result in tqdm(pool.imap(find_primes_in_range, ranges), total=len(ranges), desc="Crunching Primes"):
                primeNumberList.extend(result)

    end_time = time.time()

    print("Total primes found:", len(primeNumberList))
    print(primeNumberList)
    print("\n\nTime taken:", f"{end_time - start_time:.4f} seconds")

