#define inp(v) for (auto& x : v) cin >> x
#define outp(v) for (int i = 0, n = v.size(); i < n; i++) cout << v[i] << " \n"[i == n - 1]
#define all(v) v.begin(), v.end()
#define yes cout << "YES" << nl
#define no cout << "NO" << nl

using namespace std;

ll bin(vll &v, ll n, ll target) 
{
    ll l = 0, h = n - 1;

    while (l <= h) 
    {
        ll m = (l + h) / 2;

        if (v[m] == target)
        {
            return m + 1;
        }

        eli (v[m] < target)
        {
            l = m + 1;
        }

        el
        {
            h = m - 1;
        }
    }

    return 0;
}

int f(ll p)
{
    if (p == 0) ret 0;
    eli (p == 2) ret 1;
    ret 2;
}

void solve()
{
    ll n, s;
    cin >> n >> s;

    int c1 = 0;
    int c2 = 0;

    vll v(n);
    loop (i, 0, n)
    {
        cin >> v[i];

        if (v[i] == 1) c1++;
        eli (v[i] == 2) c2++;
    }

    ll sum = c1 + c2 * 2;

    if (sum > s)
    {
        outp(v);
        ret;
    }

    eli (sum == s)
    {
        cout << -1 << nl;
        ret;
    }

    if ((s - sum) == 1)
    {
        sort (all(v), [](ll a, ll b)
        {
            ret f(a) < f(b);
        });

        outp(v);
        ret;
    }

    cout << -1 << nl;
}



