#include <stdio.h>

char checkSort(int arr[], int n) 
{
    int asc = 1, desc = 1;
    for (int i = 1; i < n; i++) 
{
        if (arr[i] > arr[i - 1]) desc = 0;
        if (arr[i] < arr[i - 1]) asc = 0;
    }
    if (asc) return 'A';
    else if (desc) return 'D';
    else return 'U';
}

//for largest difference
int maxDifference(int arr[], int n) 
{
    int max = arr[0], min = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] > max) max = arr[i];
        if (arr[i] < min) min = arr[i];
    }
    return max - min;
}

// F sum of unique elements
int sumOfUnique(int arr[], int n) 
{
    int sum = 0;
    for (int i = 0; i < n; i++)
 {
        int isUnique = 1;
        for (int j = 0; j < n; j++)
 {
            if (i != j && arr[i] == arr[j])
 {
                isUnique = 0;
                break;
            }
        }
        if (isUnique) sum += arr[i];
    }
    return sum;
}

