#include <stdio.h>

void sortDescending(int arr[], int n) 
{
    for (int i = 0; i < n - 1; i++)
   {
        for (int j = 0; j < n - i - 1; j++)
       {
            if (arr[j] < arr[j + 1])
           {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

int calculateHindex(int C[], int N)
 {
    sortDescending(C, N); 
    int h = 0;
    for (int i = 0; i < N; i++) 
    {
        if (C[i] >= i + 1)
       {
            h = i + 1;
        }
      else
        {
            break;
        }
    }
    return h;
}

